                                          unitId: clients.length + 1,
                                          enabled: true,
                                          timeout: 5000,
                                          retries: 3,
                                          cyclicEnabled: true,
                                          cyclicInterval: 1000,
                                          registerMappings: {
                                            holdingRegisters: [],
                                            inputRegisters: [],
                                            coils: [],
                                            discreteInputs: []
                                          }
                                        };
                                        updateProtocol(protocolIndex, {
                                          settings: {
                                            ...protocol.settings,
                                            clients: [...clients, newClient]
                                          }
                                        });
                                        // Set active tab to new client
                                        setActiveRegisterTab(prev => ({
                                          ...prev,
