                                      } else {
                                        // Remove excess variables
                                        newVariables = newVariables.slice(0, newCount);
                                      }
                                      
                                      updateProtocol(protocolIndex, {
                                        settings: {
                                          ...protocol.settings,
                                          registerMap: {
                                            ...protocol.settings?.registerMap,
                                            holdingRegisters: {
                                              start,
                                              count: newCount,
