                                              const clients = [...(protocol.settings?.clients || [])];
                                              clients[clientIdx] = { ...client, port: parseInt(e.target.value) };
                                              updateProtocol(protocolIndex, {
                                                settings: {
                                                  ...protocol.settings,
                                                  clients
                                                }
                                              });
                                            }}
