                                            Device will only be read/written when triggered via HTTP API calls
                                          </div>
                                        </div>
                                      </div>
                                    </div>

                                    {/* Register Mappings */}
                                    <div className="client-register-mappings">
                                      <h6>Register Mappings</h6>
                                      <p style={{fontSize: '0.7rem', color: '#666', marginBottom: '1rem'}}>
